define void @store_select_with_null(i1 %cond, ptr %p) {
  %sel = select i1 %cond, ptr %p, ptr null
  store i32 0, ptr %sel, align 4
  ret void
}

define void @store_select_with_null_commuted(i1 %cond, ptr %p) {
  %sel = select i1 %cond, ptr null, ptr %p
  store i32 0, ptr %sel, align 4
  ret void
}

